detailed_optimizations.code_changes:
将更新 ey、ex 和 hz 的多个独立 i, j 嵌套循环融合为一个统一的 i, j 循环（在处理边界条件的前提下），以提高空间局部性，并使用 #pragma omp parallel for simd 引导编译器进行多线程并行化和 SIMD 向量化。修改后的核心结构如下：

for (t = 0; t < _PB_TMAX; t++) {
  // 1. 边界条件更新
  for (j = 0; j < _PB_NY; j++) ey[0][j] = _fict_[t];

  // 2. 融合 ey 和 ex 的更新
  #pragma omp parallel for collapse(2)
  for (i = 1; i < _PB_NX; i++) {
    for (j = 1; j < _PB_NY; j++) {
      ey[i][j] = ey[i][j] - 0.5f * (hz[i][j] - hz[i-1][j]);
      ex[i][j] = ex[i][j] - 0.5f * (hz[i][j] - hz[i][j-1]);
    }
  }
  // 处理 i=0 的 ex 边界和 j=0 的 ey 边界...

  // 3. 更新 hz
  #pragma omp parallel for collapse(2)
  for (i = 0; i < _PB_NX - 1; i++) {
    for (j = 0; j < _PB_NY - 1; j++) {
      hz[i][j] = hz[i][j] - 0.7f * (ex[i][j+1] - ex[i][j] + ey[i+1][j] - ey[i][j]);
    }
  }
}
